#!/usr/bin/env tsx

/**
 * Debug script to test Vision API confidence calculation directly
 */

import { assessDamageWithVision } from '@/lib/integrations/vision-damage-detection';

async function testVisionConfidence() {
  console.log('🔍 Testing Vision API confidence calculation...');

  try {
    const result = await assessDamageWithVision([
      'data:image/jpeg;base64,',
      'data:image/jpeg;base64,',
      'data:image/jpeg;base64,'
    ]);

    console.log('✅ Vision API Result:');
    console.log(`   Confidence Score: ${result.confidenceScore}% (should be 0-100)`);
    console.log(`   Labels: ${result.labels.join(', ')}`);
    console.log(`   Damage Percentage: ${result.damagePercentage}%`);
    console.log(`   Method: ${result.method}`);

    if (result.confidenceScore > 100) {
      console.log('❌ Confidence score is too high!');
    } else {
      console.log('✅ Confidence score is within expected range');
    }

  } catch (error) {
    console.error('❌ Vision API test failed:', error);
  }
}

testVisionConfidence().catch(console.error);